#include <stdio.h>
#include <stdlib.h>
#define MAX 1000
int max(int a, int b) { return a > b ? a : b; }
int min(int a, int b) { return a < b ? a : b; }
int abs(int a) { return a < 0 ? -a : a; }
int main() {
    int T, N, M, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &M, &K);
        int A[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &A[i][j]);
            }
        }
        int dp[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                dp[i][j] = 0;
            }
        }
        for (int i = 0; i < M; i++) {
            dp[0][i] = A[0][i];
        }
        for (int i = 1; i < N; i++) {
            for (int j = 0; j < M; j++) {
                int maxVal = -1000000;
                for (int k = max(0, j - K); k <= min(M - 1, j + K); k++) {
                    maxVal = max(maxVal, dp[i - 1][k]);
                }
                dp[i][j] = maxVal + A[i][j];
            }
        }
        int maxScore = -1000000;
        for (int i = 0; i < M; i++) {
            maxScore = max(maxScore, dp[N - 1][i]);
        }
        printf("%d\n", maxScore);
    }
    return 0;
}

