import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int K = sc.nextInt();
            int[][] A = new int[N][M];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    A[i][j] = sc.nextInt();
                }
            }
            int[][] dp = new int[N][M];
            for (int i = 0; i < M; i++) {
                dp[0][i] = A[0][i];
            }
            for (int i = 1; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    int maxVal = -1000000;
                    for (int k = Math.max(0, j - K); k <= Math.min(M - 1, j + K); k++) {
                        maxVal = Math.max(maxVal, dp[i - 1][k]);
                    }
                    dp[i][j] = maxVal + A[i][j];
                }
            }
            int maxScore = -1000000;
            for (int i = 0; i < M; i++) {
                maxScore = Math.max(maxScore, dp[N - 1][i]);
            }
            System.out.println(maxScore);
        }
    }
}

